import "./App.css";
import React, { useState, useEffect } from "react";

function App() {
  const [tasks, setTasks] = useState([]);
  const [task, setTask] = useState("");
  const [priority, setPriority] = useState("Medium");
  const [dueDate, setDueDate] = useState("");

  // Add Task
  const addTask = async () => {
    try {
      const response = await fetch("http://localhost:5000/addTask", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          task,
          priority,
          dueDate,
        }),
      });

      const data = await response.json();
      console.log(data);

      alert("Task Added Successfully");

      // clear inputs
      setTask("");
      setPriority("Medium");
      setDueDate("");

      // refresh task list
      fetchTasks();
    } catch (error) {
      console.log(error);
    }
  };

  // Fetch Tasks
  const fetchTasks = async () => {
    try {
      const response = await fetch("http://localhost:5000/tasks");
      const data = await response.json();
      setTasks(data);
    } catch (error) {
      console.log(error);
    }
  };

  // Run when page loads
  useEffect(() => {
    fetchTasks();
  }, []);

  //delete task
  const deleteTask = async (id) => {
    try {
      await fetch(`http://localhost:5000/deleteTask/${id}`, {
        method: "DELETE",
      });

      alert("Task Deleted");

      fetchTasks(); // refresh list
    } catch (error) {
      console.log(error);
    }
  };

  //updating task status to completed
  const updateTask = async (id) => {
    try {
      await fetch(`http://localhost:5000/updateTask/${id}`, {
        method: "PUT",
      });

      alert("Task Marked as Completed");

      fetchTasks(); // refresh list
    } catch (error) {
      console.log(error);
    }
  };
  return (
    <div style={{ padding: "20px" }}>
      <h1>Task Manager</h1>

      {/* Input */}
      <input
        type="text"
        placeholder="Enter task"
        value={task}
        onChange={(e) => setTask(e.target.value)}
      />

      <br />
      <br />

      {/* Priority */}
      <select value={priority} onChange={(e) => setPriority(e.target.value)}>
        <option>High</option>
        <option>Medium</option>
        <option>Low</option>
      </select>

      <br />
      <br />

      {/* Due Date */}
      <input
        type="date"
        value={dueDate}
        onChange={(e) => setDueDate(e.target.value)}
      />

      <br />
      <br />

      {/* Button */}
      <button onClick={addTask}>Add Task</button>

      <hr />

      {/* Task List */}
      <h2>Task List</h2>

      <ul>
        {tasks.map((t) => (
          <li key={t._id}>
            {t.task} - {t.priority} - {t.status}
            {/* Complete Button */}
            {t.status === "Pending" && (
              <button
                style={{ marginLeft: "10px" }}
                onClick={() => updateTask(t._id)}
              >
                Complete
              </button>
            )}
            {/* Delete Button */}
            <button
              style={{ marginLeft: "10px" }}
              onClick={() => deleteTask(t._id)}
            >
              Delete
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default App;
